//комментарий
var comment = "комментарий";

//устанавливаем трудозатраты 
PublicAPI.Portal.TaskBase.Task.SetFactWorkLog(taskId, days, startDate, comment);

//создаем структуру CompleteTaskModel и заполняем её
var model = new CompleteTaskModel();
//заполняем поле "оповещать соисполнителей"
model.alertCoexecuters = true;
//заполняем поле "Дата начала"
model.startDate = DateTime.Now;
//заполняем поле "Трудозатраты" (в минутах)
model.worklogMinutes = 120;
//создаем ICommentActionModel
var commentModel = InterfaceActivator.Create<ICommentActionModel>();
//создаем объект IComment
var comment = InterfaceActivator.Create<IComment>();
//заполняем поле "Текст комментария"
comment.Text = "Комменатрий";
//заполняем поле "Дата создания"
comment.CreationDate = DateTime.Now;
//заполняем поле "Автор комментария"
comment.CreationAuthor = PublicAPI.Portal.Security.User.GetCurrentUser();
//сохраняем комменатрий
comment.Save();
//заполняем поле "Комментарий"
commentModel.Comment = comment;
//заполняем поле CommentActionModel
model.actionModel = commentModel;

//завершаем задачу
PublicAPI.Portal.TaskBase.Task.CompleteTask(taskId, model);

member.remarks:
* - Обязательные параметры Параметры: [0]*: Интервал рабочего времени (WorkTime)
Результат: Возвращает отформатированное значение интервала рабочего времени в днях, часах и минутах
Пример: Пусть WorkLogItem - переменная типа "Запись в отчете о трудозатратах". Чтобы вернуть значение фактического отработанного времени (FactWorkTime): {WorkTimeToFormatString({$WorkLogItem.FactWorkTime})}

* - Обязательные параметры Параметры: [0]*: Запись в отчете о трудозатратах (IWorkLogItem)
Результат: Возвращает загруженную сущность
Пример: Пусть WorkLogItem - переменная типа "Запись в отчете о трудозатратах". В качестве объекта трудозатрат была выбрана задача Task. Чтобы загрузить Task через WorkLogItem: {LoadEntityByWorkLogItem({$WorkLogItem})}

* - Обязательные параметры Параметры: [0]*: Запись в отчете о трудозатратах (IWorkLogItem)
Результат: Строка, содержащая отображаемое имя сущности
Пример: Пусть WorkLogItem - переменная типа "Запись в отчете о трудозатратах". В качестве объекта трудозатрат была выбрана задача Task. Чтобы получить отображаемое имя Task через WorkLogItem: {GetEntityDisplayNameByWorkLogItem({$WorkLogItem})}
